// frontend/src/pages/MyTasks.js — ПОЛНОСТЬЮ ЗАМЕНИТЬ
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import Sidebar from '../components/Sidebar';
import api from '../api';

function TaskRow({ task }) {
  const [expanded, setExpanded] = useState(false);
  const navigate = useNavigate();

  return (
    <div style={{ background: 'white', border: '1px solid #e2e8e0', borderRadius: 14, overflow: 'hidden' }}>
      {/* Заголовок строки — кликабельный */}
      <div onClick={() => setExpanded(v => !v)} style={{ padding: '16px 20px', display: 'flex', alignItems: 'center', gap: 14, cursor: 'pointer' }}>
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#8a9e87" strokeWidth="2.5"
          style={{ flexShrink: 0, transition: 'transform 0.18s', transform: expanded ? 'rotate(90deg)' : 'rotate(0)' }}>
          <polyline points="9 18 15 12 9 6"/>
        </svg>
        <div style={{ width: 10, height: 10, borderRadius: '50%', flexShrink: 0, background: task.status === 'open' ? '#16a34a' : task.status === 'in_progress' ? '#d97706' : '#0284c7' }} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontWeight: 600, fontSize: 15, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{task.title}</div>
          <div style={{ fontSize: 12, color: '#8a9e87', marginTop: 2, display: 'flex', gap: 10 }}>
            {task.category && <span>{task.category}</span>}
            <span>{new Date(task.created_at).toLocaleDateString('en-US', { day: 'numeric', month: 'short' })}</span>
          </div>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexShrink: 0 }}>
          {task.payment && <span style={{ fontWeight: 700, color: '#2d6a27', fontSize: 14 }}>{task.payment} ₸</span>}
          <span className={`badge badge-${task.status}`}>
            {task.status === 'open' ? 'Open' : task.status === 'in_progress' ? 'In Progress' : 'Done'}
          </span>
        </div>
      </div>

      {/* Раскрытые детали */}
      {expanded && (
        <div style={{ padding: '0 20px 18px', borderTop: '1px solid #e2e8e0' }}>
          <div style={{ paddingTop: 16, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
            {task.description && (
              <div style={{ gridColumn: '1 / -1' }}>
                <div style={{ fontSize: 11, fontWeight: 600, color: '#8a9e87', textTransform: 'uppercase', letterSpacing: 0.4, marginBottom: 4 }}>Description</div>
                <p style={{ fontSize: 14, color: '#4a5548', lineHeight: 1.6 }}>{task.description}</p>
              </div>
            )}
            {task.location_name && (
              <div>
                <div style={{ fontSize: 11, fontWeight: 600, color: '#8a9e87', textTransform: 'uppercase', letterSpacing: 0.4, marginBottom: 4 }}>Location</div>
                <div style={{ fontSize: 14 }}>{task.location_name}</div>
              </div>
            )}
            {task.helper_name && (
              <div>
                <div style={{ fontSize: 11, fontWeight: 600, color: '#8a9e87', textTransform: 'uppercase', letterSpacing: 0.4, marginBottom: 4 }}>Helper</div>
                <div style={{ fontSize: 14, fontWeight: 500 }}>{task.helper_name}</div>
              </div>
            )}
          </div>
          <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
            <button className="btn btn-primary btn-sm"
              onClick={() => navigate(task.status === 'in_progress' ? `/tasks/${task.id}/status` : `/tasks/${task.id}`)}>
              {task.status === 'in_progress' ? 'View Status' : 'Open Task'}
            </button>
            {task.status === 'in_progress' && (
              <button className="btn btn-secondary btn-sm" onClick={() => navigate(`/chat/${task.id}`)}>
                Open Chat
              </button>
            )}
            {task.status === 'completed' && task.helper_id && (
              <button className="btn btn-secondary btn-sm" onClick={() => navigate(`/tasks/${task.id}/rate`)}>
                Leave Review
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default function MyTasks() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    if (!user) { navigate('/signin'); return; }
    api.get('/tasks/my').then(r => setTasks(r.data)).catch(() => {}).finally(() => setLoading(false));
  }, [user]);

  const filtered = filter === 'all' ? tasks : tasks.filter(t => t.status === filter);
  const counts = { all: tasks.length, open: tasks.filter(t => t.status === 'open').length, in_progress: tasks.filter(t => t.status === 'in_progress').length, completed: tasks.filter(t => t.status === 'completed').length };

  return (
    <div className="app-layout">
      <Sidebar />
      <div className="main-content">
        <div className="page-topbar">
          <span className="page-topbar-title">My Tasks</span>
          <button className="btn btn-primary btn-sm" onClick={() => navigate('/create-task')}>+ New Task</button>
        </div>
        <div className="page-body">
          <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
            {[['all','All'],['open','Open'],['in_progress','In Progress'],['completed','Completed']].map(([k,l]) => (
              <button key={k} className={`chip ${filter === k ? 'active' : ''}`} onClick={() => setFilter(k)}>
                {l} <span style={{ marginLeft: 5, opacity: 0.65, fontSize: 11 }}>{counts[k]}</span>
              </button>
            ))}
          </div>

          {loading && <div className="loading-wrap"><div className="spinner" /></div>}

          {!loading && filtered.length === 0 && (
            <div style={{ textAlign: 'center', padding: '64px 20px' }}>
              <p style={{ color: '#8a9e87', fontSize: 14, marginBottom: 16 }}>
                {filter === 'all' ? 'No tasks yet' : `No ${filter.replace('_', ' ')} tasks`}
              </p>
              <button className="btn btn-primary btn-sm" onClick={() => navigate('/create-task')}>Create a task</button>
            </div>
          )}

          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {filtered.map(task => <TaskRow key={task.id} task={task} />)}
          </div>
        </div>
      </div>
    </div>
  );
}
